    37  // Register registers the metrics in the current PrometheusMetrics into the provided registry
    38  func (m *PrometheusMetrics) Register(registry prometheus.Registerer) error {
    39          for _, collector := range []prometheus.Collector{
    40                  m.requestsCounter, m.failureCounter, m.durationSecondsHistogram, m.inFlightGauge,
    41          } {
    42                  if err := registry.Register(collector); err != nil {
    43                          return err
    44                  }
    45          }
    46          return nil
    47  }
    48
    49  // MustRegister is like Register, but, in case of failure, it panics instead of returning an error
    50  func (m *PrometheusMetrics) MustRegister(registry prometheus.Registerer) {
    51          if err := m.Register(registry); err != nil {
    52                  panic(err)
    53          }
    54  }
