    37  func (s *Service) detectPrometheusVariants(ctx context.Context) (map[string]int64, error) {
    38          if s.promFlavorCache.memoized.Add(promFlavorCacheLifetime).After(time.Now()) &&
    39                  s.promFlavorCache.variants != nil {
    40                  return s.promFlavorCache.variants, nil
    41          }
    42
    43          dsProm := &datasources.GetDataSourcesByTypeQuery{Type: "prometheus"}
    44          dataSources, err := s.datasources.GetDataSourcesByType(ctx, dsProm)
    45          if err != nil {
    46                  s.log.Error("Failed to read all Prometheus data sources", "error", err)
    47                  return nil, err
    48          }
    49
    50          g, ctx := errgroup.WithContext(ctx)
    51          g.SetLimit(10)
    52          flavors := sync.Map{}
    53
    54          for _, ds := range dataSources {
    55                  ds := ds
    56                  g.Go(func() error {
    57                          variant, err := s.detectPrometheusVariant(ctx, ds)
    58                          if err != nil {
    59                                  return err
    60                          }
    61                          flavors.Store(ds.UID, variant)
    62                          return nil
    63                  })
    64          }
    65          if err := g.Wait(); err != nil {
    66                  return nil, err
    67          }
    68
    69          variants := map[string]int64{}
    70
    71          flavors.Range(func(_, value any) bool {
    72                  variant, ok := value.(string)
    73                  if !ok {
    74                          return true
    75                  }
    76
    77                  if variant == "" {
    78                          return true
    79                  }
    80
    81                  if _, exists := variants[variant]; !exists {
    82                          variants[variant] = 0
    83                  }
    84                  variants[variant] += 1
    85                  return true
    86          })
    87
    88          s.promFlavorCache.variants = variants
    89          s.promFlavorCache.memoized = time.Now()
    90          return variants, nil
    91  }
