    93  func (s *Service) detectPrometheusVariant(ctx context.Context, ds *datasources.DataSource) (string, error) {
    94          // 5s timeout
    95          ctx, cancel := context.WithTimeout(ctx, 5*time.Second)
    96          defer cancel()
    97
    98          type buildInfo struct {
    99                  Data struct {
   100                          Application *string        `json:"application"`
   101                          Features    map[string]any `json:"features"`
   102                  } `json:"data"`
   103          }
   104          c, err := s.datasources.GetHTTPTransport(ctx, ds, s.httpClientProvider)
   105          if err != nil {
   106                  s.log.Error("Failed to get HTTP client for Prometheus data source", "error", err)
   107                  return "", err
   108          }
   109
   110          req, err := http.NewRequestWithContext(ctx, http.MethodGet, ds.URL+"/api/v1/status/buildinfo", nil)
   111          if err != nil {
   112                  s.log.Error("Failed to create Prometheus build info request", "error", err)
   113                  return "", err
   114          }
   115
   116          resp, err := c.RoundTrip(req)
   117          if err != nil {
   118                  // Possibly configuration error, the risk of a false positive is
   119                  // too high.
   120                  s.log.Debug("Failed to send Prometheus build info request", "error", err)
   121                  return "unreachable", nil
   122          }
   123          defer func() {
   124                  err := resp.Body.Close()
   125                  if err != nil {
   126                          s.log.Error("Got error while closing response body")
   127                  }
   128          }()
   129
   130          if resp.StatusCode == 404 {
   131                  return "cortex-like", nil
   132          }
   133
   134          if resp.StatusCode != 200 {
   135                  return "unknown", nil
   136          }
   137
   138          body, err := io.ReadAll(resp.Body)
   139          if err != nil {
   140                  s.log.Error("Failed to read Prometheus build info", "error", err)
   141                  return "", err
   142          }
   143
   144          bi := &buildInfo{}
   145          err = json.Unmarshal(body, bi)
   146          if err != nil {
   147                  s.log.Warn("Failed to read Prometheus build info JSON", "error", err)
   148                  return "", err
   149          }
   150
   151          if bi.Data.Application != nil && *bi.Data.Application == "Grafana Mimir" {
   152                  return "mimir", nil
   153          }
   154
   155          if bi.Data.Features != nil {
   156                  return "mimir-like", nil
   157          }
   158
   159          return "vanilla", nil
   160  }

