    11  // SanitizeLabelName removes all invalid chars from the label name.
    12  // If the label name is empty or contains only invalid chars, it
    13  // will return an error.
    14  func SanitizeLabelName(name string) (string, error) {
    15          if len(name) == 0 {
    16                  return "", errors.New("label name cannot be empty")
    17          }
    18
    19          out := strings.Builder{}
    20          for i, b := range name {
    21                  if (b >= 'a' && b <= 'z') || (b >= 'A' && b <= 'Z') || b == '_' || (b >= '0' && b <= '9' && i > 0) {
    22                          out.WriteRune(b)
    23                  } else if b == ' ' {
    24                          out.WriteRune('_')
    25                  }
    26          }
    27
    28          if out.Len() == 0 {
    29                  return "", fmt.Errorf("label name only contains invalid chars: %q", name)
    30          }
    31
    32          return out.String(), nil
    33  }
