    41  }
    42
    43  // NewCounterVecStartingAtZero initializes a new Prometheus counter with an initial
    44  // observation of zero for every possible value of each label. Used for the sake of
    45  // consistency among all the possible labels and values.
    46  func NewCounterVecStartingAtZero(opts prometheus.CounterOpts, labels []string, labelValues map[string][]string) *prometheus.CounterVec {
    47          counter := prometheus.NewCounterVec(opts, labels)
    48
    49          for _, ls := range buildLabelSets(labels, labelValues) {
    50                  counter.With(ls).Add(0)
    51          }
    52
    53          return counter
    54  }
    55
    56  func buildLabelSets(labels []string, labelValues map[string][]string) []prometheus.Labels {
    57          var labelSets []prometheus.Labels
    58
    59          var n func(i int, ls prometheus.Labels)
    60          n = func(i int, ls prometheus.Labels) {
    61                  if i == len(labels) {
    62                          labelSets = append(labelSets, ls)
    63                          return
    64                  }
    65
    66                  label := labels[i]
    67                  values := labelValues[label]
    68
    69                  for _, v := range values {
    70                          lsCopy := copyLabelSet(ls)
    71                          lsCopy[label] = v
    72                          n(i+1, lsCopy)
    73                  }
    74          }
    75
    76          n(0, prometheus.Labels{})
    77          return labelSets
    78  }
    79
    80  func copyLabelSet(ls prometheus.Labels) prometheus.Labels {
    81          newLs := make(prometheus.Labels, len(ls))
    82          for l, v := range ls {
    83                  newLs[l] = v
    84          }
    85          return newLs
    86  }

